use super::*;
use crate::Console;
use crate::controller::{
    StandardControllerState, decode_standard_controller_state, encode_standard_controller_state,
    read_standard_controller_port, write_standard_controller_port,
};
use nerust_contract_core::options::CoreOptions;
use nerust_contract_core::options::Mmc3IrqVariant;
use nerust_input_nes::frame::Buttons;
use nerust_input_nes_runtime::ControllerState;
use nerust_screen_video::FilterType;
use nerust_screen_video::LogicalSize;
use nerust_contract_core::audio::AudioBackend;
use std::time::Duration;

const CONSOLE_STATE_FIXTURE_HEX: &str = "";

#[derive(Clone, Default)]
struct TestSpeaker;

impl AudioBackend for TestSpeaker {
    fn start(&mut self) {}
    fn pause(&mut self) {}
    fn push(&mut self, _data: f32) {}
}

#[derive(Debug, Default)]
struct TestControllerRuntime {
    state: StandardControllerState,
}

impl nerust_nes_core::controller::Controller for TestControllerRuntime {
    fn read(&mut self, address: usize) -> nerust_nes_core::OpenBusReadResult {
        read_standard_controller_port(&mut self.state, address)
    }

    fn write(&mut self, value: u8) {
        write_standard_controller_port(&mut self.state, value);
    }
}

impl ControllerState for TestControllerRuntime {
    fn reset_runtime(&mut self) {
        self.state = StandardControllerState::default();
    }

    fn validate_controller_state(&self, bytes: &[u8]) -> Result<(), String> {
        decode_standard_controller_state(bytes).map(|_| ())
    }

    fn apply_controller_state(&mut self, bytes: &[u8]) -> Result<(), String> {
        self.state = decode_standard_controller_state(bytes)?;
        Ok(())
    }

    fn current_controller_state(&self) -> Result<Vec<u8>, String> {
        encode_standard_controller_state(self.state)
    }
}

#[derive(Debug, Default)]
struct OpaqueControllerRuntime {
    controller_state: Vec<u8>,
    input_state: Vec<u8>,
}

impl nerust_nes_core::controller::Controller for OpaqueControllerRuntime {
    fn read(&mut self, _address: usize) -> nerust_nes_core::OpenBusReadResult {
        nerust_nes_core::OpenBusReadResult::new(0, 0)
    }

    fn write(&mut self, _value: u8) {}
}

impl ControllerState for OpaqueControllerRuntime {
    fn reset_runtime(&mut self) {
        self.controller_state.clear();
        self.input_state.clear();
    }

    fn validate_controller_state(&self, _bytes: &[u8]) -> Result<(), String> {
        Ok(())
    }

    fn apply_controller_state(&mut self, bytes: &[u8]) -> Result<(), String> {
        self.controller_state = bytes.to_vec();
        Ok(())
    }

    fn current_controller_state(&self) -> Result<Vec<u8>, String> {
        Ok(self.controller_state.clone())
    }
}

fn fixture_bytes(hex: &str) -> Vec<u8> {
    assert!(
        !hex.trim().is_empty(),
        "fixture hex must be populated before running console tests"
    );
    let hex = hex.trim();
    assert_eq!(hex.len() % 2, 0, "fixture hex length must be even");
    hex.as_bytes()
        .chunks_exact(2)
        .map(|chunk| {
            let text = std::str::from_utf8(chunk).expect("fixture hex should be valid utf-8");
            u8::from_str_radix(text, 16).expect("fixture hex should decode")
        })
        .collect()
}

fn decode_console_state(bytes: &[u8]) -> ConsoleStatePayload {
    rmp_serde::from_slice(bytes).expect("console state should decode")
}

fn decode_controller_snapshot(bytes: &[u8]) -> StandardControllerState {
    decode_standard_controller_state(bytes).expect("controller state should decode")
}

fn decode_legacy_console_state(bytes: &[u8]) -> LegacyConsoleStatePayload {
    rmp_serde::from_slice(bytes).expect("legacy console state should decode")
}

fn test_rom_bytes() -> Vec<u8> {
    let mut rom = vec![
        0x4E, 0x45, 0x53, 0x1A, 0x02, 0x01, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
        0x00,
    ];
    rom.resize(16 + 0x8000 + 0x2000, 0);
    rom
}

fn test_console() -> Console {
    test_console_with_controller(Box::new(TestControllerRuntime::default()))
}

fn test_console_with_controller(controller: Box<dyn ControllerState>) -> Console {
    Console::new_gpu(
        TestSpeaker::default(),
        FilterType::None,
        LogicalSize {
            width: 2,
            height: 1,
        },
        controller,
    )
}

fn loaded_console() -> Console {
    let console = test_console();
    console
        .load(test_rom_bytes())
        .expect("test ROM should load into console");
    std::thread::sleep(Duration::from_millis(20));
    console
}

fn loaded_console_with_controller(controller: Box<dyn ControllerState>) -> Console {
    let console = test_console_with_controller(controller);
    console
        .load(test_rom_bytes())
        .expect("test ROM should load into console");
    std::thread::sleep(Duration::from_millis(20));
    console
}

fn export_console_state(console: &Console) -> ConsoleStatePayload {
    decode_console_state(
        &console
            .export_state()
            .expect("console state should export")
            .state_blob,
    )
}

#[test]
fn console_state_fixture_import_restores_wrapper_state() {
    let bytes = fixture_bytes(CONSOLE_STATE_FIXTURE_HEX);
    let fixture = decode_legacy_console_state(&bytes);
    assert_eq!(fixture.schema_version, LEGACY_CONSOLE_STATE_SCHEMA_VERSION);
    assert_eq!(fixture.frame_counter, 9);
    assert!(fixture.paused);
    assert_eq!(fixture.source_frame, vec![3, 5]);

    let mut console = loaded_console();
    // 初期フレームのコマンドを消費し、ACK を復帰させる
    console.swap_frame_buffer();
    console
        .import_state(bytes)
        .expect("fixture console state should import");
    let exported = export_console_state(&console);
    assert_eq!(exported.schema_version, CONSOLE_STATE_SCHEMA_VERSION);
    assert_eq!(exported.frame_counter, fixture.frame_counter);
    assert_eq!(exported.paused, fixture.paused);
    assert_eq!(
        decode_controller_snapshot(&exported.controller_state),
        StandardControllerState {
            buttons: [
                Buttons::from_bits_retain(fixture.controller.pad1_bits as u8),
                Buttons::from_bits_retain(fixture.controller.pad2_bits as u8),
            ],
            microphone: fixture.controller.microphone,
            index1: fixture.controller.index1 as usize,
            index2: fixture.controller.index2 as usize,
            strobe: fixture.controller.strobe,
        }
    );
    assert_eq!(exported.source_frame, fixture.source_frame);
    assert_eq!(exported.rom_identity, fixture.rom_identity);
    assert_eq!(exported.options, fixture.options);
    console.swap_frame_buffer();
    console.with_frame_buffer(|frame| assert_eq!(frame, fixture.source_frame));
}

#[test]
fn console_state_imports_previous_v2_schema() {
    let console = loaded_console();
    let current = export_console_state(&console);
    let snapshot = decode_controller_snapshot(&current.controller_state);
    let payload = StructuredConsoleStatePayload {
        schema_version: STRUCTURED_CONSOLE_STATE_SCHEMA_VERSION,
        core_state: current.core_state,
        frame_counter: current.frame_counter,
        paused: current.paused,
        controller: StructuredControllerStatePayload {
            ports: [
                StructuredControllerPortStatePayload {
                    input_bits: u32::from(snapshot.buttons[0].bits()),
                    index: snapshot.index1 as u64,
                },
                StructuredControllerPortStatePayload {
                    input_bits: u32::from(snapshot.buttons[1].bits()),
                    index: snapshot.index2 as u64,
                },
            ],
            auxiliary: StructuredControllerAuxiliaryStatePayload {
                microphone: snapshot.microphone,
            },
            strobe: snapshot.strobe,
        },
        rom_identity: current.rom_identity,
        options: current.options,
        source_frame: current.source_frame,
    };

    console
        .import_state(rmp_serde::to_vec_named(&payload).expect("payload should encode"))
        .expect("v2 console state should import");

    assert_eq!(
        decode_controller_snapshot(&export_console_state(&console).controller_state),
        snapshot
    );
}

#[test]
fn console_state_export_import_round_trip_preserves_wrapper_fields() {
    let console = loaded_console();
    let original = console.export_state().expect("console state should export");

    console
        .import_state(original.state_blob.clone())
        .expect("console state should import");

    let exported = console
        .export_state()
        .expect("console state should re-export");
    let original_payload = decode_console_state(&original.state_blob);
    let exported_payload = decode_console_state(&exported.state_blob);
    assert_eq!(
        exported_payload.frame_counter,
        original_payload.frame_counter
    );
    assert_eq!(exported_payload.paused, original_payload.paused);
    assert_eq!(
        decode_controller_snapshot(&exported_payload.controller_state),
        decode_controller_snapshot(&original_payload.controller_state)
    );
    assert_eq!(exported_payload.source_frame, original_payload.source_frame);
}

#[test]
fn console_state_import_accepts_runtime_owned_controller_payloads() {
    let template = loaded_console();
    let export = template
        .export_state()
        .expect("console state should export");
    let mut payload = decode_console_state(&export.state_blob);
    payload.controller_state = vec![0xDE, 0xAD, 0xBE, 0xEF];
    let bytes = rmp_serde::to_vec_named(&payload).expect("payload should encode");

    let console = loaded_console_with_controller(Box::new(OpaqueControllerRuntime::default()));
    console
        .import_state(bytes)
        .expect("opaque controller payload should import");

    let exported = export_console_state(&console);
    assert_eq!(exported.controller_state, vec![0xDE, 0xAD, 0xBE, 0xEF]);
}

#[test]
fn console_state_import_restores_paused_frame_counter_controller_and_source_frame() {
    let mut console = loaded_console();
    let export = console.export_state().expect("console state should export");
    let mut payload = decode_console_state(&export.state_blob);
    payload.frame_counter = 42;
    payload.paused = true;
    payload.controller_state = encode_standard_controller_state(StandardControllerState {
        buttons: [Buttons::A | Buttons::START, Buttons::LEFT],
        microphone: true,
        index1: 3,
        index2: 5,
        strobe: true,
    })
    .expect("controller state should encode");
    payload.source_frame = vec![11, 29];
    let bytes = rmp_serde::to_vec_named(&payload).expect("payload should encode");

    // 初期フレームのコマンドを消費し、ACK を復帰させる
    console.swap_frame_buffer();
    console
        .import_state(bytes)
        .expect("console state should import");

    let exported = export_console_state(&console);
    assert_eq!(exported.frame_counter, 42);
    assert!(exported.paused);
    assert_eq!(
        decode_controller_snapshot(&exported.controller_state),
        StandardControllerState {
            buttons: [Buttons::A | Buttons::START, Buttons::LEFT],
            microphone: true,
            index1: 3,
            index2: 5,
            strobe: true,
        }
    );
    assert_eq!(exported.source_frame, vec![11, 29]);
    console.swap_frame_buffer();
    console.with_frame_buffer(|frame| assert_eq!(frame, &[11, 29]));
}

#[test]
fn console_state_rejects_schema_mismatch() {
    let console = loaded_console();
    let export = console.export_state().expect("console state should export");
    let mut payload = decode_console_state(&export.state_blob);
    payload.schema_version += 1;
    let bytes = rmp_serde::to_vec_named(&payload).expect("payload should encode");

    let error = console
        .import_state(bytes)
        .expect_err("schema mismatch should reject");
    assert!(
        error
            .to_string()
            .contains("unsupported console state schema version")
    );
}

#[test]
fn console_state_rejects_invalid_controller_payload() {
    let console = loaded_console();
    let export = console.export_state().expect("console state should export");
    let mut payload = decode_console_state(&export.state_blob);
    payload.controller_state = vec![0x01, 0x02, 0x03];
    let bytes = rmp_serde::to_vec_named(&payload).expect("payload should encode");

    let error = console
        .import_state(bytes)
        .expect_err("invalid controller payload should reject");
    assert!(!error.to_string().is_empty());
}

#[test]
fn console_state_rejects_wrapper_rom_identity_mismatch() {
    let console = loaded_console();
    let export = console.export_state().expect("console state should export");
    let mut payload = decode_console_state(&export.state_blob);
    payload.rom_identity.prg_rom_crc64 ^= 1;
    let bytes = rmp_serde::to_vec_named(&payload).expect("payload should encode");

    let error = console
        .import_state(bytes)
        .expect_err("wrapper ROM identity mismatch should reject");
    assert!(error.to_string().contains("console ROM identity mismatch"));
}

#[test]
fn console_state_rejects_wrapper_option_mismatch() {
    let console = loaded_console();
    let export = console.export_state().expect("console state should export");
    let mut payload = decode_console_state(&export.state_blob);
    payload.options = CoreOptions {
        mmc3_irq_variant: Some(Mmc3IrqVariant::Sharp),
    };
    let bytes = rmp_serde::to_vec_named(&payload).expect("payload should encode");

    let error = console
        .import_state(bytes)
        .expect_err("wrapper runtime options mismatch should reject");
    assert!(
        error
            .to_string()
            .contains("console runtime options mismatch")
    );
}

#[test]
fn console_state_failed_import_does_not_mutate_existing_state() {
    let console = loaded_console();
    let before = console.export_state().expect("console state should export");
    let mut payload = decode_console_state(&before.state_blob);
    payload.controller_state = vec![0x01, 0x02, 0x03];
    let bytes = rmp_serde::to_vec_named(&payload).expect("payload should encode");

    console
        .import_state(bytes)
        .expect_err("invalid controller payload should reject");

    let after = console
        .export_state()
        .expect("console state should still export");
    let before_payload = decode_console_state(&before.state_blob);
    let after_payload = decode_console_state(&after.state_blob);
    assert_eq!(after_payload.frame_counter, before_payload.frame_counter);
    assert_eq!(after_payload.paused, before_payload.paused);
    assert_eq!(
        decode_controller_snapshot(&after_payload.controller_state),
        decode_controller_snapshot(&before_payload.controller_state)
    );
    assert_eq!(after_payload.source_frame, before_payload.source_frame);
}
